export function matchTourConfig(pathname: string): string | null {
  if (pathname === '/dashboard') return 'dashboard'
  if (pathname === '/workspace') return 'workspace'
  if (pathname === '/workspace/lesson-prep') return 'lesson-prep'
  if (pathname === '/workspace/worksheet') return 'worksheet'
  if (pathname === '/workspace/quiz-generator') return 'quiz'
  if (pathname === '/workspace/lesson-planner') return 'lesson-planner'
  if (pathname === '/workspace/presentations') return 'presentations'
  if (pathname === '/workspace/vocabulary') return 'vocabulary'
  if (pathname === '/workspace/image') return 'image'
  if (pathname === '/workspace/games') return 'games'
  if (pathname === '/workspace/messages') return 'messages'
  if (pathname === '/dashboard/courses') return 'courses'
  if (pathname === '/dashboard/students') return 'students'
  if (pathname === '/dashboard/grading') return 'grading'
  if (pathname === '/dashboard/analytics') return 'analytics'
  if (pathname === '/dashboard/referrals') return 'referrals'
  if (pathname === '/dashboard/settings') return 'settings'
  if (pathname === '/dashboard/assignments') return 'assignments-list'
  if (/^\/dashboard\/assignments\/[^/]+$/.test(pathname)) return 'assignment-overview'
  if (/^\/dashboard\/classes\/[^/]+$/.test(pathname)) return 'class-detail'
  if (/^\/dashboard\/students\/[^/]+$/.test(pathname)) return 'student-profile'
  if (pathname === '/student/dashboard') return 'student-dashboard'
  if (pathname === '/student/assignments') return 'student-assignments'
  if (pathname === '/student/grades') return 'student-grades'
  if (pathname === '/student/achievements') return 'student-achievements'
  if (pathname === '/student/ai-teacher') return 'student-ai-teacher'
  return null
}
